const express = require('express');
const httpProxy = require('http-proxy');
const bodyParser = require('body-parser');
const PluginManager = require('./pluginManager');

const app = express();
const port = process.env.PORT || 3000;
const target = process.env.TARGET || 'http://localhost:3001'; // Default upstream target for proxying

// Create a proxy server instance
const proxy = httpProxy.createProxyServer({
    target: target,
    changeOrigin: true, // Changes the origin header to the target URL
    selfHandleResponse: true, // Crucial for intercepting and modifying the response body
});

// Initialize the plugin manager
const pluginManager = new PluginManager();

// Asynchronous setup for loading plugins and starting the gateway
(async () => {
    // Load plugins from environment variables and a local directory
    await pluginManager.loadPlugins({
        pluginsJsonEnvVar: 'GATEWAY_PLUGINS_JSON', // Environment variable name containing JSON array of plugin definitions
        pluginsDir: './plugins', // Directory to scan for .js plugin files
    });

    console.log(`API Gateway running with ${pluginManager.plugins.length} plugins.`);
    if (pluginManager.plugins.length > 0) {
        console.log('Registered plugin names:', pluginManager.plugins.map(p => p.name).join(', '));
    }

    // Middleware to parse incoming request bodies
    app.use(bodyParser.json());
    app.use(bodyParser.urlencoded({ extended: true }));
    app.use(bodyParser.text()); // For plain text bodies
    app.use(bodyParser.raw()); // For raw buffer bodies

    // Main request handler for all incoming traffic
    app.all('*', (req, res, next) => {
        // 1. Execute onRequest hooks from plugins
        pluginManager.executeRequestPlugins(req, res, (err) => {
            if (res.headersSent) {
                console.log('Request terminated by a plugin (response already sent).');
                return; // A plugin has already sent a response, so stop processing
            }
            if (err) {
                console.error('Error during onRequest plugin execution:', err);
                // Pass the error to Express's default error handler or custom handler
                return next(err);
            }

            // If no plugin terminated the request, proceed with proxying
            console.log(`Proxying request to ${target}${req.url}`);
            proxy.web(req, res, {}, (e) => {
                if (e) {
                    console.error('Proxy error (during proxy.web to upstream):', e.message);
                    // Handle proxy errors via plugins
                    pluginManager.executeErrorPlugins(e, req, res, () => {
                        if (!res.headersSent) {
                            res.status(502).send(`Bad Gateway: ${e.message}`);
                        }
                    });
                }
            });
        });
    });

    // 2. Handle responses received from the upstream server
    proxy.on('proxyRes', (proxyRes, req, res) => {
        console.log(`Received response from upstream for ${req.url}. Status: ${proxyRes.statusCode}`);

        // Buffer the entire response body from the upstream
        let bodyChunks = [];
        proxyRes.on('data', (chunk) => {
            bodyChunks.push(chunk);
        });

        proxyRes.on('end', () => {
            const originalBody = Buffer.concat(bodyChunks).toString('utf8');
            console.log(`Original response body length: ${originalBody.length} bytes.`);

            // Copy all original headers from the upstream response to the client response,
            // except for 'content-length' and 'transfer-encoding' which might change if body is modified.
            Object.keys(proxyRes.headers).forEach(header => {
                if (!['content-length', 'transfer-encoding'].includes(header.toLowerCase())) {
                    res.setHeader(header, proxyRes.headers[header]);
                }
            });
            res.statusCode = proxyRes.statusCode; // Set the client response status code

            // Execute onResponse hooks from plugins
            pluginManager.executeResponsePlugins(proxyRes, req, res, originalBody, (modifiedBody) => {
                // After all onResponse plugins have run, send the final modified response to the client
                console.log(`Final response body length: ${modifiedBody.length} bytes.`);
                res.setHeader('Content-Length', Buffer.byteLength(modifiedBody, 'utf8'));
                res.end(modifiedBody);
            });
        });

        proxyRes.on('error', (e) => {
            console.error('Proxy response stream error:', e.message);
            // Handle errors during response stream via plugins
            pluginManager.executeErrorPlugins(e, req, res, () => {
                if (!res.headersSent) {
                    res.status(500).send(`Upstream Response Error: ${e.message}`);
                }
            });
        });
    });

    // 3. Handle errors that occur during the proxying process (e.g., connection refused, timeout)
    proxy.on('error', (err, req, res) => {
        console.error('Proxy error (during proxy.on("error") event): ', err.message);
        // Execute onError hooks from plugins
        pluginManager.executeErrorPlugins(err, req, res, () => {
            if (!res.headersSent) {
                // If no plugin handled the error, send a default 500
                res.status(500).send(`Proxy Error: ${err.message}`);
            }
        });
    });

    // Default Express error handler (catches errors thrown by onRequest plugins or other middleware)
    app.use((err, req, res, next) => {
        console.error('Express caught unhandled error from middleware/plugins:', err);
        // Execute onError hooks for generic Express errors
        pluginManager.executeErrorPlugins(err, req, res, () => {
            if (!res.headersSent) {
                res.status(500).send(`Internal Gateway Error: ${err.message}`);
            }
        });
    });

    // Start the API Gateway server
    app.listen(port, () => {
        console.log(`API Gateway listening on http://localhost:${port}`);
        console.log(`Proxying requests to upstream target: ${target}`);
    });

})().catch(e => {
    // Catch any errors during the async initialization process
    console.error('Failed to initialize API Gateway:', e);
    process.exit(1); // Exit with a non-zero code to indicate failure
});